using System.ComponentModel;
using System.Net.Http.Json;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.AI;

// ---------------------------------------------------------------------------
// Research Agent – searches the web, takes notes, and summarises findings
// ---------------------------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// Build the chat client pipeline with automatic function invocation
IChatClient chatClient = new ChatClientBuilder(
        new OpenAI.OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// Instantiate the tools the agent can call
var researchTools = new ResearchTools();
var tools = new AITool[]
{
    AIFunctionFactory.Create(researchTools.SearchWeb),
    AIFunctionFactory.Create(researchTools.AddNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
    AIFunctionFactory.Create(researchTools.ClearNotes),
};

var systemPrompt = """
    You are a research agent. Your job is to research a topic the user gives you
    by searching the web, collecting useful information in your notes, and then
    producing a concise, well-structured summary.

    Workflow:
    1. Break the topic into 2-3 search queries that cover different angles.
    2. For each query, call search_web and review the results.
    3. Use add_note to save the most important facts, data points, or quotes.
    4. After researching, call get_notes to review everything you collected.
    5. Write a final summary for the user with sections and source references.

    Be thorough but concise. Cite sources where possible.
    """;

// Prompt the user for a research topic
Console.ForegroundColor = ConsoleColor.Cyan;
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍  Research Agent  🔍        ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.ResetColor();
Console.WriteLine();
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.ForegroundColor = ConsoleColor.Yellow;
Console.WriteLine($"Researching: {topic}");
Console.WriteLine("This may take a moment...");
Console.ResetColor();
Console.WriteLine();

// Run the agent loop
var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}"),
};

var options = new ChatOptions { Tools = [.. tools] };

var response = await chatClient.GetResponseAsync(messages, options);

// Display the final summary
Console.ForegroundColor = ConsoleColor.Green;
Console.WriteLine("═══════════════════════════════════════");
Console.WriteLine("  Research Summary");
Console.WriteLine("═══════════════════════════════════════");
Console.ResetColor();
Console.WriteLine();
Console.WriteLine(response.Text);
Console.WriteLine();

// Show collected notes
var notes = researchTools.GetAllNotes();
if (notes.Count > 0)
{
    Console.ForegroundColor = ConsoleColor.DarkCyan;
    Console.WriteLine($"📝 {notes.Count} note(s) were collected during research.");
    Console.ResetColor();
}

// ---------------------------------------------------------------------------
// Tools available to the agent
// ---------------------------------------------------------------------------

/// <summary>
/// Provides web search and note-taking tools for the research agent.
/// </summary>
sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _httpClient = new();
    private static readonly JsonSerializerOptions s_jsonOptions = new() { PropertyNameCaseInsensitive = true };

    [Description("Search the web for information on a query. Returns a list of results with titles, URLs, and snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.ForegroundColor = ConsoleColor.DarkGray;
        Console.WriteLine($"  🔎 Searching: \"{query}\"");
        Console.ResetColor();

        try
        {
            // Use DuckDuckGo Instant Answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            _httpClient.DefaultRequestHeaders.UserAgent.Clear();
            _httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

            var response = await _httpClient.GetFromJsonAsync<JsonElement>(url);
            var results = new StringBuilder();

            // Abstract (main answer)
            var abstractText = response.GetProperty("AbstractText").GetString();
            var abstractSource = response.GetProperty("AbstractSource").GetString();
            var abstractUrl = response.GetProperty("AbstractURL").GetString();

            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.AppendLine($"## Main Result from {abstractSource}");
                results.AppendLine($"URL: {abstractUrl}");
                results.AppendLine(abstractText);
                results.AppendLine();
            }

            // Related topics
            if (response.TryGetProperty("RelatedTopics", out var relatedTopics))
            {
                var count = 0;
                foreach (var topic in relatedTopics.EnumerateArray())
                {
                    if (count >= 8)
                        break;

                    if (topic.TryGetProperty("Text", out var text) &&
                        topic.TryGetProperty("FirstURL", out var firstUrl))
                    {
                        results.AppendLine($"- {text.GetString()}");
                        results.AppendLine($"  URL: {firstUrl.GetString()}");
                        count++;
                    }
                }
            }

            var resultText = results.ToString();
            return string.IsNullOrWhiteSpace(resultText)
                ? $"No results found for \"{query}\". Try rephrasing the search."
                : resultText;
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Save a note with important information found during research. Use this to collect facts before writing the summary.")]
    public string AddNote(
        [Description("The note content to save")] string content)
    {
        _notes.Add(content);
        Console.ForegroundColor = ConsoleColor.DarkGray;
        Console.WriteLine($"  📝 Note #{_notes.Count} saved ({content.Length} chars)");
        Console.ResetColor();
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved notes collected during research.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"Note #{i + 1}: {_notes[i]}");
        }

        return sb.ToString();
    }

    [Description("Clear all saved notes to start fresh.")]
    public string ClearNotes()
    {
        var count = _notes.Count;
        _notes.Clear();
        return $"Cleared {count} note(s).";
    }

    public List<string> GetAllNotes() => [.. _notes];
}

