 using System.ComponentModel;
 using System.Net.Http.Json;
 using System.Text;
 using System.Text.Json;
 using Microsoft.Extensions.AI;

 // ---------------------------------------------------------------------------
 // Research Agent – searches the web, takes notes, and summarises findings
 // ---------------------------------------------------------------------------

 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable before running.");

 var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

 // Build the chat client pipeline with automatic function invocation
 IChatClient chatClient = new ChatClientBuilder(
         new OpenAI.OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
     .UseFunctionInvocation()
     .Build();

 // Instantiate the tools the agent can call
 var researchTools = new ResearchTools();
 var tools = new AITool[]
 {
     AIFunctionFactory.Create(researchTools.SearchWeb),
     AIFunctionFactory.Create(researchTools.AddNote),
     AIFunctionFactory.Create(researchTools.GetNotes),
     AIFunctionFactory.Create(researchTools.ClearNotes),
 };

 var systemPrompt = """
     You are a research agent. Your job is to research a topic the user gives you
     by searching the web, collecting useful information in your notes, and then
     producing a concise, well-structured summary.

     Workflow:
     1. Break the topic into 2-3 search queries that cover different angles.
     2. For each query, call search_web and review the results.
     3. Use add_note to save the most important facts, data points, or quotes.
     4. After researching, call get_notes to review everything you collected.
     5. Write a final summary for the user with sections and source references.

     Be thorough but concise. Cite sources where possible.
     """;

 // Prompt the user for a research topic
 Console.ForegroundColor = ConsoleColor.Cyan;
 Console.WriteLine("╔══════════════════════════════════════╗");
 Console.WriteLine("║       🔍  Research Agent  🔍        ║");
 Console.WriteLine("╚══════════════════════════════════════╝");
 Console.ResetColor();
 Console.WriteLine();
 Console.Write("Enter a topic to research: ");
 var topic = Console.ReadLine()?.Trim();

 if (string.IsNullOrWhiteSpace(topic))
 {
     Console.WriteLine("No topic provided. Exiting.");
     return;
 }

 Console.WriteLine();
 Console.ForegroundColor = ConsoleColor.Yellow;
 Console.WriteLine($"Researching: {topic}");
 Console.WriteLine("This may take a moment...");
 Console.ResetColor();
 Console.WriteLine();

 // Run the agent loop
 var messages = new List<ChatMessage>
 {
     new(ChatRole.System, systemPrompt),
     new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}"),
 };

 var options = new ChatOptions { Tools = [.. tools] };

 var response = await chatClient.GetResponseAsync(messages, options);

 // Display the final summary
 Console.ForegroundColor = ConsoleColor.Green;
 Console.WriteLine("═══════════════════════════════════════");
 Console.WriteLine("  Research Summary");
 Console.WriteLine("═══════════════════════════════════════");
 Console.ResetColor();
 Console.WriteLine();
 Console.WriteLine(response.Text);
 Console.WriteLine();

 // Show collected notes
 var notes = researchTools.GetAllNotes();
